// ── backtestData.js ────────────────────────────────────────
// Fetches historical monthly price data from FMP for
// backtesting. Uses the same API key as marketData.js.

const API_KEY  = process.env.REACT_APP_FMP_KEY;
const BASE_URL = "https://financialmodelingprep.com/api/v3";

// Cache historical data — it doesn't change so we keep it
// for the full session
const historyCache = {};

// ── Fetch monthly closing prices for one ticker ────────────
// Returns [{ date: "YYYY-MM", close: 123.45 }, ...]
export async function fetchMonthlyPrices(ticker, years = 5) {
  if (historyCache[ticker]) return historyCache[ticker];

  const url = `${BASE_URL}/historical-price-full/${ticker}?serietype=line&apikey=${API_KEY}`;
  const res  = await fetch(url);
  if (!res.ok) throw new Error(`Price fetch failed for ${ticker}`);

  const data = await res.json();
  if (!data.historical?.length) throw new Error(`No price history for ${ticker}`);

  // FMP returns daily — resample to monthly (last trading day of each month)
  const cutoff = new Date();
  cutoff.setFullYear(cutoff.getFullYear() - years);

  const monthly = {};
  data.historical
    .filter(d => new Date(d.date) >= cutoff)
    .forEach(d => {
      const key = d.date.slice(0, 7); // "YYYY-MM"
      // Keep the earliest entry per month (FMP is reverse-chronological)
      // so the last overwrite will be the month's final trading day
      monthly[key] = d.close;
    });

  const result = Object.entries(monthly)
    .map(([date, close]) => ({ date, close }))
    .sort((a, b) => a.date.localeCompare(b.date));

  historyCache[ticker] = result;
  return result;
}

// ── Fetch prices for multiple tickers + SPY benchmark ──────
// Returns { prices: { AAPL: [...], ... }, benchmark: [...] }
export async function fetchBacktestData(tickers, years = 5) {
  const allTickers = [...new Set([...tickers, "SPY"])];

  const results = await Promise.allSettled(
    allTickers.map(t => fetchMonthlyPrices(t, years))
  );

  const prices    = {};
  const errors    = [];

  allTickers.forEach((ticker, i) => {
    if (results[i].status === "fulfilled") {
      prices[ticker] = results[i].value;
    } else {
      errors.push(ticker);
      console.warn(`Failed to fetch history for ${ticker}:`, results[i].reason?.message);
    }
  });

  const benchmark = prices["SPY"] ?? [];
  delete prices["SPY"];

  return { prices, benchmark, errors };
}
